// Code Generated by Sidekick is for learning and experimentation purposes only.
/**
 * Chat Interface JavaScript
 * Updated for Conversational Agent System with Workflow and Event Creation Agents
 */

class ChatInterface {
    constructor() {
        this.isWaitingForResponse = false;
        this.apiBaseUrl = '/api/agent';
        this.conversationInitialized = false;
        this.currentAgentType = null;
        this.firstMessageSent = false;  // Track if user has sent first message
        
        this.messageInput = document.getElementById('user-input');
        this.sendButton = document.getElementById('send-button');
        this.chatMessages = document.getElementById('chat-messages');
        this.typingIndicator = document.getElementById('typing-indicator');
        this.charCount = document.getElementById('char-count');
        
        this.init();
    }
    
    init() {
        console.log('[ChatInterface] Initializing...');
        
        // Initialize chat session but dont show greeting yet
        this.startSession();
        
        // Event listeners
        this.sendButton.addEventListener('click', () => this.sendMessage());
        this.messageInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                this.sendMessage();
            }
        });
        
        // Auto-resize textarea
        this.messageInput.addEventListener('input', () => {
            this.messageInput.style.height = 'auto';
            this.messageInput.style.height = this.messageInput.scrollHeight + 'px';
            this.updateCharCount();
        });
        
        console.log('[ChatInterface] Initialized');
    }
    
    async startSession() {
        console.log('[ChatInterface] Starting conversation...');
        
        try {
            const response = await fetch(`${this.apiBaseUrl}/start`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                }
            });
            
            console.log('[ChatInterface] Start response status:', response.status);
            
            const data = await response.json();
            console.log('[ChatInterface] Start response data:', data);
            
            if (data.success) {
                this.conversationInitialized = true;
                console.log('[ChatInterface] ✅ Conversation started successfully');
                
                // DON'T remove welcome screen yet
                // DON'T display greeting message yet
                // Just mark conversation as ready
                
                // Store the greeting for later (when user sends first message)
                this.initialGreeting = {
                    response: data.response,
                    agent_type: data.agent_type
                };
                
                console.log('[ChatInterface] Welcome screen will remain until first user message');
                
            } else {
                console.error('[ChatInterface] ❌ Failed to start:', data.error);
                this.showError('Failed to start chat session: ' + (data.error || 'Unknown error'));
            }
        } catch (error) {
            console.error('[ChatInterface] ❌ Error starting session:', error);
            
            // Don't show error for browser-related 404s
            if (error.message && !error.message.includes('well-known')) {
                this.showError('Connection error. Please refresh the page.');
            } else {
                console.log('[ChatInterface] Ignoring browser-related error');
            }
        }
    }
    
    async sendMessage() {
        const message = this.messageInput.value.trim();
        
        if (!message || this.isWaitingForResponse) return;
        
        if (!this.conversationInitialized) {
            console.error('[ChatInterface] No active conversation');
            this.showError('Chat not initialized. Please refresh the page.');
            return;
        }
        
        console.log('[ChatInterface] Sending message:', message);
        
        // If this is the first message, remove welcome screen and show greeting
        if (!this.firstMessageSent) {
            console.log('[ChatInterface] First message - removing welcome screen');
            this.removeWelcomeScreen();
            
            // Show the initial greeting now
            if (this.initialGreeting) {
                this.displayMessage(
                    this.initialGreeting.response,
                    'bot',
                    this.initialGreeting.agent_type
                );
                this.showAgentIndicator(this.initialGreeting.agent_type);
            }
            
            this.firstMessageSent = true;
        }
        
        // Display user message
        this.displayMessage(message, 'user');
        
        // Clear input
        this.messageInput.value = '';
        this.messageInput.style.height = 'auto';
        this.updateCharCount();
        
        // Show typing indicator
        this.showTypingIndicator();
        this.isWaitingForResponse = true;
        this.sendButton.disabled = true;
        
        try {
            const response = await fetch(`${this.apiBaseUrl}/chat`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    message: message
                })
            });
            
            console.log('[ChatInterface] Chat response status:', response.status);
            
            const data = await response.json();
            console.log('[ChatInterface] Chat response data:', data);
            
            this.hideTypingIndicator();
            
            if (data.success) {
                // Update current agent type
                this.currentAgentType = data.agent_type;
                
                // Display bot response with agent type
                this.displayMessage(data.response, 'bot', data.agent_type);
                
                // Show which agent is responding
                this.showAgentIndicator(data.agent_type);
                
                // Handle special cases based on agent type
                if (data.agent_type === 'event_creation') {
                    // Check if event was created
                    if (data.event_created) {
                        this.showSuccessNotification('Event created successfully!');
                    }
                    
                    // Check if in collection mode
                    if (data.collecting_info) {
                        console.log('[ChatInterface] Collecting event information...');
                    }
                } else if (data.agent_type === 'information') {
                    // Workflow agent is handling information query
                    console.log('[ChatInterface] Information query processed');
                    
                    // Could show different UI indicators for multi-stage processing
                    if (data.processing_stage) {
                        console.log('[ChatInterface] Processing stage:', data.processing_stage);
                    }
                }
                
                // Show context if available (for debugging)
                if (data.context) {
                    console.log('[ChatInterface] Conversation context:', data.context);
                }
                
            } else {
                console.error('[ChatInterface] ❌ Chat error:', data.error);
                this.displayMessage(
                    data.response || 'Sorry, I encountered an error. Please try again.',
                    'bot',
                    'error'
                );
            }
        } catch (error) {
            console.error('[ChatInterface] ❌ Error sending message:', error);
            this.hideTypingIndicator();
            this.displayMessage(
                'Sorry, I encountered a connection error. Please try again.',
                'bot',
                'error'
            );
        } finally {
            this.isWaitingForResponse = false;
            this.sendButton.disabled = false;
            this.messageInput.focus();
        }
    }
    
    displayMessage(text, sender, agentType = null) {
        console.log('[displayMessage] Called with:', {
            sender,
            agentType,
            textPreview: text.substring(0, 100)
        });
        
        const messageDiv = document.createElement('div');
        messageDiv.className = `message ${sender}`;
        
        const avatar = document.createElement('div');
        avatar.className = `message-avatar ${sender === 'bot' ? 'bot-avatar' : 'user-avatar'}`;
        
        // Different icons based on agent type
        if (sender === 'bot') {
            if (agentType === 'event_creation') {
                avatar.innerHTML = '<i class="fas fa-calendar-plus"></i>';
                avatar.title = 'Event Creation Agent';
            } else if (agentType === 'information') {
                avatar.innerHTML = '<i class="fas fa-info-circle"></i>';
                avatar.title = 'Information Agent';
            } else if (agentType === 'greeting') {
                avatar.innerHTML = '<i class="fas fa-robot"></i>';
                avatar.title = 'SPIC MACAY Assistant';
            } else {
                avatar.innerHTML = '<i class="fas fa-robot"></i>';
            }
        } else {
            avatar.innerHTML = '<i class="fas fa-user"></i>';
        }
        
        const contentDiv = document.createElement('div');
        contentDiv.className = 'message-content';
        
        const bubble = document.createElement('div');
        bubble.className = 'message-bubble';
        
        // Format the message text (preserve line breaks)
        bubble.innerHTML = this.formatMessageText(text);
        
        const time = document.createElement('div');
        time.className = 'message-time';
        
        // Add agent type label for bot messages
        if (sender === 'bot' && agentType) {
            const agentLabel = this.getAgentLabel(agentType);
            time.innerHTML = `
                <span class="agent-label">${agentLabel}</span>
                <span>${new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
            `;
        } else {
            time.textContent = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        }
        
        contentDiv.appendChild(bubble);
        contentDiv.appendChild(time);
        
        if (sender === 'bot') {
            messageDiv.appendChild(avatar);
            messageDiv.appendChild(contentDiv);
        } else {
            messageDiv.appendChild(contentDiv);
            messageDiv.appendChild(avatar);
        }
        
        this.chatMessages.appendChild(messageDiv);
        this.scrollToBottom();
    }
    
    formatMessageText(text) {
        // Convert line breaks to <br> tags
        // Preserve formatting from the agent
        return text
            .replace(/\n/g, '<br>')
            .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')  // Bold
            .replace(/\*(.*?)\*/g, '<em>$1</em>');  // Italic
    }
    
    getAgentLabel(agentType) {
        const labels = {
            'event_creation': '📅 Event Creation',
            'information': 'ℹ️ Information',
            'greeting': '👋 Welcome',
            'error': '⚠️ Error'
        };
        return labels[agentType] || '🤖 Assistant';
    }
    
    showAgentIndicator(agentType) {
        // Show which agent is currently active
        const indicator = document.getElementById('agent-indicator');
        if (indicator) {
            if (agentType === 'event_creation') {
                indicator.innerHTML = '<i class="fas fa-calendar-plus"></i> Event Creation Mode';
                indicator.className = 'agent-indicator event-mode';
            } else if (agentType === 'information') {
                indicator.innerHTML = '<i class="fas fa-info-circle"></i> Information Mode';
                indicator.className = 'agent-indicator info-mode';
            } else {
                indicator.innerHTML = '<i class="fas fa-robot"></i> Assistant';
                indicator.className = 'agent-indicator default-mode';
            }
        }
    }
    
    showTypingIndicator() {
        this.typingIndicator.classList.add('active');
        this.scrollToBottom();
    }
    
    hideTypingIndicator() {
        this.typingIndicator.classList.remove('active');
    }
    
    removeWelcomeScreen() {
        const welcomeScreen = document.getElementById('welcome-screen');
        if (welcomeScreen) {
            console.log('[ChatInterface] Removing welcome screen');
            welcomeScreen.remove();
        }
    }
    
    scrollToBottom() {
        setTimeout(() => {
            this.chatMessages.scrollTop = this.chatMessages.scrollHeight;
        }, 100);
    }
    
    updateCharCount() {
        const count = this.messageInput.value.length;
        this.charCount.textContent = `${count}/1000`;
        
        if (count > 900) {
            this.charCount.style.color = '#dc3545';
        } else {
            this.charCount.style.color = '#666';
        }
    }
    
    showError(message) {
        console.error('[ChatInterface] Error:', message);
        
        const toast = document.getElementById('errorToast');
        const toastBody = document.getElementById('errorToastBody');
        
        if (toast && toastBody) {
            toastBody.textContent = message;
            const bsToast = new bootstrap.Toast(toast);
            bsToast.show();
        } else {
            // Fallback if toast doesn't exist
            alert(message);
        }
    }
    
    showSuccessNotification(message) {
        console.log('[ChatInterface] Success:', message);
        
        const toast = document.getElementById('successToast');
        const toastBody = document.getElementById('successToastBody');
        
        if (toast && toastBody) {
            toastBody.textContent = message;
            const bsToast = new bootstrap.Toast(toast);
            bsToast.show();
        }
    }
}

// Global functions for button clicks
function startWithMessage(message) {
    console.log('[Global] Starting with message:', message);
    if (window.chatInterface) {
        window.chatInterface.messageInput.value = message;
        window.chatInterface.sendMessage();
    }
}

async function resetChat() {
    console.log('[Global] Resetting chat...');
    
    if (!window.chatInterface) {
        console.error('[Global] Chat interface not initialized');
        return;
    }
    
    if (confirm('Are you sure you want to reset the conversation?')) {
        try {
            const response = await fetch('/api/agent/reset', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                }
            });
            
            console.log('[Global] Reset response status:', response.status);
            
            const data = await response.json();
            console.log('[Global] Reset response data:', data);
            
            if (data.success) {
                // Clear messages
                window.chatInterface.chatMessages.innerHTML = '';
                
                // Re-add welcome screen
                const welcomeScreen = document.createElement('div');
                welcomeScreen.id = 'welcome-screen';
                welcomeScreen.className = 'welcome-screen';
                welcomeScreen.innerHTML = `
                   
                    <h3>Welcome to SPIC MACAY Event Assistant! 🎵</h3>
                    <p>Speak or type to register events and manage activities</p>
                    
                    <div class="feature-grid">
                        <div class="feature-card" onclick="startWithMessage('I want to register a new event')">
                            <i class="fas fa-calendar-plus"></i>
                            <h5>Register Events</h5>
                            <p>Create and manage SPIC MACAY events</p>
                        </div>
                        <div class="feature-card" onclick="startWithMessage('Tell me about SPIC MACAY')">
                            <i class="fas fa-info-circle"></i>
                            <h5>Get Information</h5>
                            <p>Ask about events, venues, and more</p>
                        </div>
                        <div class="feature-card" onclick="startVoiceMode()" title="Click to see what I can do">
                            <i class="fas fa-robot"></i>
                            <h5>Voice Assistant Mode</h5>
                            <p>Speak to discuss</p>
                        </div>
                    </div>
                </div>
            </div>
            
                `;
                window.chatInterface.chatMessages.appendChild(welcomeScreen);
                
                // Reset first message flag
                window.chatInterface.firstMessageSent = false;
                
                console.log('[Global] ✅ Chat reset successfully');
                
                // Restart conversation
                await window.chatInterface.startSession();
            } else {
                console.error('[Global] ❌ Reset failed:', data.error);
                window.chatInterface.showError('Failed to reset chat');
            }
        } catch (error) {
            console.error('[Global] ❌ Error resetting chat:', error);
            window.chatInterface.showError('Error resetting chat');
        }
    }
}

async function getConversationHistory() {
    console.log('[Global] Getting conversation history...');
    
    try {
        const response = await fetch('/api/agent/history', {
            method: 'GET',
            headers: {
                'Content-Type': 'application/json'
            }
        });
        
        const data = await response.json();
        console.log('[Global] History:', data);
        
        return data.history;
    } catch (error) {
        console.error('[Global] ❌ Error getting history:', error);
        return null;
    }
}

async function checkAgentStatus() {
    console.log('[Global] Checking agent status...');
    
    try {
        const response = await fetch('/api/agent/status', {
            method: 'GET',
            headers: {
                'Content-Type': 'application/json'
            }
        });
        
        const data = await response.json();
        console.log('[Global] Agent status:', data);
        
        // Show status in alert or modal
        const statusMessage = `
Agent Status:
- Initialized: ${data.initialized ? 'Yes' : 'No'}
- Current Mode: ${data.agent_type || 'None'}
- Messages: ${data.message_count || 0}
        `.trim();
        
        alert(statusMessage);
        
        return data;
    } catch (error) {
        console.error('[Global] ❌ Error checking status:', error);
        return null;
    }
}

// Initialize chat interface when DOM is loaded
document.addEventListener('DOMContentLoaded', () => {
    console.log('[Global] DOM loaded, initializing chat interface...');
    window.chatInterface = new ChatInterface();
    console.log('[Global] Chat interface ready. Welcome screen visible. Waiting for user input.');
});
